                <button
                  onClick={() => handleRemovePoin(poin.id)}
                  className="p-2 mb-[1px] text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-md transition-colors"
                  title="Hapus Poin"
                >
                  <Trash2 className="w-[18px] h-[18px]" />
                </button>
              </div>
            ))}
          </div>
        </div>

        <button 
          onClick={handleAddPoin}
          className="flex items-center gap-2 mt-4 px-5 py-2 text-[13px] font-semibold text-[#D9A500] border border-[#D9A500] hover:bg-[#D9A500] hover:text-white rounded-md transition-colors shadow-sm"
        >
          <span className="text-lg">+</span> Tambah Poin
        </button>
      </div>
    </div>
  );
}

